INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b757840-2208-5287-8fd4-6cad13b117f3', 'e02ed49b-8da2-5907-a4b1-f03b294360e6', 'ما أكبر عددٍ لا يتجاوز 50 ويقبل القسمة على 7 (باقيه 0)؟', '[{"id":"a","text":"42"},{"id":"b","text":"47"},{"id":"c","text":"49"},{"id":"d","text":"56"}]'::jsonb, 'c', 'مضاعفات 7 هي 7، 14، 21… 42، 49، 56. أكبرها الذي لا يتجاوز 50 هو 49 = 7 × 7. (أمّا 56 فيتجاوز 50.)', 1)
