INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0be85957-b4ca-53ca-a471-e1213111dcc0', 'e02ed49b-8da2-5907-a4b1-f03b294360e6', 'نريد نقل 100 شخصٍ بسيّاراتٍ تتّسع كلٌّ منها لـ 8 أشخاص. كم سيّارةً يلزم على الأقلّ؟', '[{"id":"a","text":"11"},{"id":"b","text":"12"},{"id":"c","text":"12 ونصف"},{"id":"d","text":"13"}]'::jsonb, 'd', '100 ÷ 8 = 12 والباقي 4، أي 12 سيّارة ممتلئة ويبقى 4 أشخاص يحتاجون سيّارةً إضافية. فالعدد اللازم 13 سيّارة (لا يمكن أن يكون العدد كسريًّا).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f059931d-0237-5b9d-97ee-8658be9a5c34', 'e02ed49b-8da2-5907-a4b1-f03b294360e6', 'في قسمةٍ إقليدية، المقسوم عليه 9 والخارج 7 والباقي 5. ما هو المقسوم؟', '[{"id":"a","text":"21"},{"id":"b","text":"68"},{"id":"c","text":"63"},{"id":"d","text":"72"}]'::jsonb, 'b', 'المقسوم = المقسوم عليه × الخارج + الباقي = 9 × 7 + 5 = 63 + 5 = 68. (والباقي 5 أصغر من 9، فالقسمة صحيحة.)', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7946e0cf-326e-56f5-83c4-d9431518bdbb', 'e02ed49b-8da2-5907-a4b1-f03b294360e6', 'ما خارج وباقي القسمة 34 ÷ 5؟', '[{"id":"a","text":"الخارج 6 والباقي 0"},{"id":"b","text":"الخارج 6 والباقي 2"},{"id":"c","text":"الخارج 6 والباقي 4"},{"id":"d","text":"الخارج 7 والباقي 1"}]'::jsonb, 'c', 'أكبر مضاعفٍ لـ 5 لا يتجاوز 34 هو 30 = 5 × 6، فالخارج 6 والباقي 34 − 30 = 4. تحقّق: 5 × 6 + 4 = 34 ✓.', 5)
